create table dirkspzm32.ems_konten_art (
    sid                varchar2(2 char) default '01' not null enable,
    firma_nr           number default 1 not null enable,
    ems_konto_nr       number(*, 5) not null enable,
    ems_art_name       varchar2(20 char) not null enable,
    erz_login_id       number(*, 0) not null enable,
    erz_datum          date not null enable,
    aend_login_id      number(*, 0),
    aend_datum         date,
    buch_einheit       varchar2(30 char),
    saldo              number(*, 5),
    letzte_buchung     date,
    abschluss_datum    date,
    abschluss_saldo    number(*, 5),
    abschluss_login_id number(*, 0),
    info               varchar2(500 char),
    min_saldo          number(*, 5),
    max_saldo          number(*, 5),
    id                 varchar2(32 char) default sys_guid() not null enable
);

alter table dirkspzm32.ems_konten_art
    add constraint pk_ems_konten_art primary key ( id )
        using index enable;


